def _iter_skill_files(directory: Path) -> Iterator[Path]:
    """Yield all *.md files under directory, excluding TEMPLATE.md."""
    for path in sorted(directory.rglob("*.md")):
        if path.name.upper() == "TEMPLATE.MD":
            continue
        yield path


